import 'package:flutter/material.dart';

// دليل استخدام تطبيق Alerts (تنبيهات) — مفهرس، ثلاثيّ الأبعاد، متعدّد اللغات،
// مع شرح تفصيليّ لكل عنصر (عنوان + وصف مختصر + شرح كامل بخطوات حيث يلزم).
//
// البنية مدفوعة بالبيانات: الأيقونات والألوان وحالة الطيّ مشتركة بين كل اللغات،
// ولكل لغة قائمة نصوص مسطّحة فقط (عنوان القسم ثم عنوان/وصف/شرح لكل عنصر).
class HgItem {
  final IconData icon;
  final String title;
  final String desc;
  final String detail; // شرح تفصيليّ يظهر عند فتح القسم.
  const HgItem(this.icon, this.title, this.desc, this.detail);
}

class HgSection {
  final IconData icon;
  final Color color;
  final bool expanded;
  final String title;
  final List<HgItem> items;
  const HgSection(this.icon, this.color, this.expanded, this.title, this.items);
}

class HgChrome {
  final String subtitle;
  final String items;
  final String updated;
  const HgChrome(this.subtitle, this.items, this.updated);
}

