// أيقونة + لون + حالة الطيّ لكل قسم (مشتركة بين اللغات).
const List<IconData> _sectionIcons = [
  Icons.rocket_launch,
  Icons.category,
  Icons.event_repeat,
  Icons.volume_up,
  Icons.palette,
  Icons.dashboard_customize,
  Icons.insights,
  Icons.settings_suggest,
];
const List<Color> _sectionColors = [_c1, _c2, _c3, _c6, _c5, _c4, _c7, _c8];

// أيقونات عناصر كل قسم. أعداد العناصر: [5, 7, 6, 5, 6, 5, 3, 6].
const List<List<IconData>> _itemIcons = [
  [Icons.add_circle, Icons.title, Icons.schedule, Icons.check_circle, Icons.mic],
